-- Generated by tools/build-premier-2024-roster.mjs.
-- This permanent catalogue replaces the admin profile-refresh prerequisite for market operations.
on conflict (provider, provider_external_id) do update set
  display_name = excluded.display_name, first_name = excluded.first_name, last_name = excluded.last_name,
  birth_date = excluded.birth_date, nationality = excluded.nationality, position = excluded.position,
  raw_payload = excluded.raw_payload, last_synced_at = excluded.last_synced_at, updated_at = now();

  catalogue_player_id, api_football_player_id, real_player_id, display_name, team_name, position, birth_date, nationality,
  match_status, match_confidence, current_value_minor, previous_value_minor, source_updated_at
)
select
  player.raw_payload ->> 'cataloguePlayerId', null, player.id, player.display_name, player.raw_payload ->> 'teamId', player.position,
  player.birth_date, player.nationality, 'matched', 100,
  (player.raw_payload ->> 'valueMinor')::bigint, (player.raw_payload ->> 'previousValueMinor')::bigint, now()
from public.real_players player
where player.provider = 'fpl-catalogue'
on conflict (catalogue_player_id) do update set
  real_player_id = coalesce(player_catalogue_profiles.real_player_id, excluded.real_player_id), display_name = excluded.display_name, team_name = excluded.team_name,
  position = excluded.position, birth_date = excluded.birth_date, nationality = excluded.nationality,
  match_status = excluded.match_status, match_confidence = excluded.match_confidence,
  current_value_minor = excluded.current_value_minor, previous_value_minor = excluded.previous_value_minor,
  source_updated_at = excluded.source_updated_at, updated_at = now();
